// Parse BankRate HTML
const html = $input.item.json.body;
const products = [];

// Extract loan products using regex patterns
// This is a simplified example - actual implementation needs robust HTML parsing
const productPattern = /<div class="product-card"[^>]*>(.*?)<\/div>/gs;
const matches = [...html.matchAll(productPattern)];

for (const match of matches) {
  const productHtml = match[1];

  // Extract product details
  const nameMatch = productHtml.match(/<h3[^>]*>(.*?)<\/h3>/);
  const rateMatch = productHtml.match(/([0-9.]+)%\s*APR/);
  const minIncomeMatch = productHtml.match(/\$([0-9,]+)\s*min\s*income/i);
  const minScoreMatch = productHtml.match(/([0-9]+)\s*min\s*credit/i);

  if (nameMatch && rateMatch) {
    products.push({
      product_name: nameMatch[1].trim(),
      provider: 'BankRate Listed',
      interest_rate: parseFloat(rateMatch[1]),
      min_income: minIncomeMatch ? parseFloat(minIncomeMatch[1].replace(/,/g, '')) : 0,
      min_credit_score: minScoreMatch ? parseInt(minScoreMatch[1]) : 600,
      min_age: 18,
      source_url: 'https://www.bankrate.com/loans/personal-loans/',
      last_updated: new Date().toISOString()
    });
  }
}

// Return array of products
return products.map(p => ({ json: p }));

// Parse NerdWallet HTML
const html = $input.item.json.body;
const products = [];

// Extract loan products from JSON-LD or structured data
try {
  const jsonLdMatch = html.match(/<script type="application\/ld\+json">(.*?)<\/script>/s);
  if (jsonLdMatch) {
    const data = JSON.parse(jsonLdMatch[1]);
    // Process structured data
  }
} catch (e) {
  console.log('JSON-LD parsing failed, using regex fallback');
}

// Fallback: Extract using patterns
const listingPattern = /<div class="listing-item"[^>]*>(.*?)<\/div>/gs;
const listings = [...html.matchAll(listingPattern)];

for (const listing of listings) {
  const content = listing[1];

  const nameMatch = content.match(/<h2[^>]*>(.*?)<\/h2>/);
  const rateMatch = content.match(/([0-9.]+)%/);
  const amountMatch = content.match(/Up to \$([0-9,]+)/);

  if (nameMatch && rateMatch) {
    products.push({
      product_name: nameMatch[1].trim(),
      provider: 'NerdWallet Listed',
      interest_rate: parseFloat(rateMatch[1]),
      min_income: 35000,
      min_credit_score: 650,
      min_age: 18,
      max_loan_amount: amountMatch ? parseFloat(amountMatch[1].replace(/,/g, '')) : null,
      source_url: 'https://www.nerdwallet.com/best/loans/personal-loans',
      last_updated: new Date().toISOString()
    });
  }
}

return products.map(p => ({ json: p }));

// Log crawl results
const itemCount = $input.all().length;
const timestamp = new Date().toISOString();

console.log(`Loan Product Discovery completed at ${timestamp}`);
console.log(`Total products discovered: ${itemCount}`);

return [{
  json: {
    success: true,
    products_count: itemCount,
    timestamp: timestamp,
    message: `Successfully discovered and stored ${itemCount} loan products`
  }
}];
